-- ============================================================
-- Local-dev seed. Runs automatically after migrations on
-- `supabase db reset`. NEVER applied to prod (Supabase ignores
-- supabase/seed.sql for remote pushes).
--
-- Login: admin@local.test / password
--
-- Stores / vendors / inventory_items below are PULLED FROM PROD
-- via read-only SELECT queries against the linked Supabase project,
-- formatted via Postgres `format('%L', ...)`. Vendor PII fields
-- (contact_name, phone, email) are masked with non-real
-- placeholders before being written to this file. Audit-log entries
-- at the bottom are still synthetic — they reference text item names
-- (no FK to inventory_items), so they keep working.
-- ============================================================

-- ─── admin user ──────────────────────────────────────────
-- gotrue's Go scanner cannot read NULL for the *_token columns even
-- though the columns are nullable. Setting them to '' (empty string)
-- avoids "Database error querying schema" on /token requests.
do $$
declare
  admin_id constant uuid := '11111111-1111-1111-1111-111111111111';
begin
    id, instance_id, aud, role,
    email, encrypted_password,
    email_confirmed_at, created_at, updated_at,
    raw_app_meta_data, raw_user_meta_data,
    is_super_admin, is_anonymous,
    confirmation_token, recovery_token,
    email_change_token_new, email_change,
    email_change_token_current, phone_change,
    phone_change_token, reauthentication_token
  ) values (
    admin_id,
    '00000000-0000-0000-0000-000000000000',
    'authenticated', 'authenticated',
    'admin@local.test',
    crypt('password', gen_salt('bf')),
    now(), now(), now(),
    jsonb_build_object(
      'provider', 'email',
      'providers', array['email'],
      'role', 'admin'
    ),
    '{}'::jsonb,
    false, false,
    '', '', '', '', '', '', '', ''
  )
  on conflict (id) do nothing;

    id, user_id, provider_id, identity_data, provider,
    last_sign_in_at, created_at, updated_at
  ) values (
    gen_random_uuid(), admin_id, admin_id::text,
    jsonb_build_object('sub', admin_id::text, 'email', 'admin@local.test', 'email_verified', true),
    'email', now(), now(), now()
  )
  on conflict (provider_id, provider) do nothing;

  values (admin_id, 'Local Admin', 'admin', 'LA', '#378ADD', 'active')
  on conflict (id) do nothing;
end $$;

-- ─── real prod stores ────────────────────────────────────
-- 4 stores from prod. Towson's id matches what init_schema
-- already inserts; the ON CONFLICT makes that row a no-op.
-- Charles / Frederick / Reisters are added here.
on conflict (id) do nothing;

-- Drop the synthetic Baltimore store that init_schema seeds.
-- Real prod doesn't have it, so we keep local in sync.
delete from public.stores where id = '00000000-0000-0000-0000-000000000002';

-- ─── grant admin access to all real stores ───────────────
select '11111111-1111-1111-1111-111111111111', id from public.stores
on conflict do nothing;

-- ─── real prod vendors (PII masked) ──────────────────────
-- 11 vendors. contact_name / phone / email replaced with
-- non-real placeholders. account_number, lead_time_days,
-- categories, delivery_days, order_cutoff_time kept real.
on conflict (id) do nothing;

-- ─── real prod inventory_items ───────────────────────────
-- 572 rows (143 per store × 4 stores).
on conflict (id) do nothing;

-- ─── real prod recipe tree ───────────────────────────────
-- 6 tables pulled from prod (read-only): recipe_categories,
-- recipes, prep_recipes, recipe_ingredients,
-- prep_recipe_ingredients, recipe_prep_items.
--
-- prep_recipes has self-referential parent_id (versioning chain) and
-- prep_recipe_ingredients has self-referential sub_recipe_id; both
-- can point to rows that haven't been inserted yet within this batch.
-- We disable FK checks for the duration of the recipe seed via
-- session_replication_role=replica (postgres superuser only — fine
-- locally, never runs in prod since seed.sql isn't pushed).
--
-- prep_recipes.created_by FK to profiles is also dropped from the
-- column list — real prod admin UUIDs don't exist locally.
set session_replication_role = replica;

on conflict (id) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

on conflict (id) do nothing;

set session_replication_role = origin;

-- ─── audit log (recent activity for the dashboard card) ──
-- Synthetic. References Towson's id (still valid) and item
-- names as text (no FK). Keeps the dashboard activity card
-- populated for visual testing.
on conflict do nothing;
